          Effect.succeed(
            makeErrorResponse({
              status: 500,
              code: "ChatInternalError",
              message: "Internal chat route error",
            })
          )
        )
      )
    )
  );

export const makeChatRouteLayer = <R = never>(options: ChatRouteOptions<R>) =>
  HttpRouter.add("POST", "/api/chat", makeChatRouteHandler(options));
